from flask import Flask, request, jsonify
from web3 import Web3
import json

app = Flask(__name__)

# Connect to Ethereum node using Web3.py
web3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    try:
        data = request.json
        message = data.get('message')
        signature = data.get('signature')
        expected_address = data.get('address')

        # Encode message as required by Ethereum
        message_hash = web3.sha3(text=message)
        prefixed_message = web3.soliditySha3(
            ['string', 'bytes32'],
            ['\x19Ethereum Signed Message:\n32', message_hash])

        # Recover the address using EIP-191 format
        recovered_address = web3.eth.account.recoverHash(prefixed_message, signature=signature)

        if recovered_address.lower() == expected_address.lower():
            return jsonify({'status': 'success', 'message': 'Address verified successfully!'}), 200
        else:
            return jsonify({'status': 'fail', 'message': 'Address verification failed!'}), 401

    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)